{
    int n;std::cin>>n;
    for(int i=1;i<=n;i++){
        std::cin>>arr[i];
    }
    std::vector<int>dp(n+31,0),next(n+13);
    dp[0]=1;
    for(int i=1;i<=n;i++){
        next[i]=0,next[i+1]=-1;
        for(int j=i-1,len=0;j>=1;j--){
            while(len!=-1&&arr[i-len]!=arr[j]){
                len=next[i+1-len];
            }
            next[j]=++len;
